window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-passenger"] = window.COURSE_LANG["cdl-passenger"] || {};
window.COURSE_LANG["cdl-passenger"]["es"] = [
  {"id":1,"q":"Al inspeccionar un autobús, debes comprobar que cada salida de emergencia:","opts":["Esté soldada por seguridad","Esté bloqueada con equipaje","Funcione y que su señal o luz de salida de emergencia funcione","Esté pintada por encima"],"re":"Cada salida de emergencia y su señal o luz deben revisarse y funcionar antes del viaje."},
  {"id":2,"q":"Debes inspeccionar el autobús y reportar cualquier defecto:","opts":["Antes de cada viaje","Solo una vez al mes","Solo después de un choque","Nunca, si se ve limpio"],"re":"Inspecciona el autobús antes de cada viaje y reporta cualquier defecto para que lo reparen."},
  {"id":3,"q":"En la inspección del autobús, los asientos de pasajeros se revisan para confirmar que:","opts":["Estén retirados del autobús","Estén apilados en el pasillo","Miren solo hacia atrás","Estén bien sujetos en su lugar"],"re":"Los asientos deben estar firmes y sujetos para que no se suelten y lesionen a los pasajeros."},
  {"id":4,"q":"Los pasamanos, los escalones y el piso deben inspeccionarse para verificar:","opts":["La estación de radio correcta","Buen estado, sin riesgo de tropiezos ni resbalones","Solo una capa nueva de cera","Portavasos adicionales"],"re":"Pasamanos, escalones y piso deben estar en condición segura para que nadie tropiece ni resbale."},
  {"id":5,"q":"El equipo de emergencia requerido en un autobús debe estar:","opts":["Dejado en la terminal","Guardado lejos del conductor","Presente y en buen estado de funcionamiento","Compartido con otro autobús"],"re":"Verifica que el equipo de emergencia requerido esté presente y utilizable antes de conducir."},
  {"id":6,"q":"Como parte de la inspección, el interior del autobús debe tener:","opts":["Ningún objeto suelto que pueda lesionar a los pasajeros","Herramientas sueltas en el tablero","Cajas apiladas junto a la puerta","Equipaje en el pasillo"],"re":"Los objetos sueltos pueden salir disparados y lesionar en una frenada fuerte; el interior debe estar despejado."},
  {"id":7,"q":"Los dispositivos de señalización, como el medio para que los pasajeros avisen al conductor, deben:","opts":["Estar desconectados","Ignorarse en la inspección","Usarse como claxon","Revisarse para confirmar que funcionan"],"re":"Los dispositivos de señalización de pasajeros deben revisarse para que puedan avisar al conductor cuando haga falta."},
  {"id":8,"q":"Junto con los frenos de servicio, la inspección del autobús debe incluir:","opts":["Los portavasos","El freno de estacionamiento y los sistemas de frenos","El color de la tela de los asientos","Los carteles de publicidad"],"re":"El freno de estacionamiento y los sistemas de frenos son elementos críticos que revisar antes de cada viaje."},
  {"id":9,"q":"Si encuentras un defecto de seguridad en la inspección previa al viaje, debes:","opts":["Repararlo o reportarlo antes de conducir","Conducir igual y arreglarlo después","Taparlo con cinta y seguir","Dejar que un pasajero lo arregle"],"re":"Los defectos que afectan la seguridad deben repararse o reportarse antes de conducir el autobús."},
  {"id":10,"q":"La línea de pasajeros de pie (standee line) en el piso del autobús marca el lugar donde:","opts":["Solo se aborda","Ningún pasajero puede pararse por delante de ella","Debe apilarse el equipaje","Se sienta el conductor"],"re":"Ningún pasajero puede pararse por delante de la línea; mantiene a los de pie lejos del conductor y el parabrisas."},
  {"id":11,"q":"El equipaje de mano en un autobús debe:","opts":["Bloquear el pasillo para acceso rápido","Apilarse en los asientos traseros","Nunca bloquear el pasillo ni ninguna salida de emergencia","Sostenerse en el regazo del conductor"],"re":"El equipaje de mano no debe bloquear el pasillo ni ninguna salida de emergencia para poder moverse y salir con seguridad."},
  {"id":12,"q":"Un pasajero no debe sentarse en un asiento que:","opts":["Tenga ventana","Esté cerca del centro","Mire hacia adelante","Haría que el pasajero bloquee una salida de emergencia salvo que esté bien asegurada"],"re":"Los pasajeros no deben sentarse donde bloquearían una salida de emergencia, salvo que esa zona esté bien asegurada."},
  {"id":13,"q":"Los materiales peligrosos en un autobús están:","opts":["Generalmente no permitidos, con solo excepciones limitadas","Siempre permitidos","Guardados con los pasajeros","Exigidos por ley"],"re":"Los materiales peligrosos por lo general no se permiten en un autobús, salvo cantidades pequeñas o de emergencia."},
  {"id":14,"q":"Nunca debes llevar entre tus pasajeros:","opts":["Una cantidad de materiales peligrosos que requiera rótulo","Una botella de agua sellada","Un periódico doblado","Un paraguas pequeño"],"re":"Nunca lleves una cantidad de materiales peligrosos que requiera rótulo entre los pasajeros del autobús."},
  {"id":15,"q":"Cuando los pasajeros necesitan conocer las reglas de seguridad, el conductor debe:","opts":["Quedarse callado todo el viaje","Repartir un manual largo para leer","Informar a los pasajeros sobre las reglas cuando haga falta","Dejar que adivinen"],"re":"Informa a los pasajeros sobre las reglas de seguridad cuando haga falta para que viajen seguros y dejen libre el pasillo."},
  {"id":16,"q":"Para permitir el movimiento y la salida seguros, el pasillo del autobús debe:","opts":["Mantenerse despejado","Llenarse de bolsas","Usarse como asientos extra","Bloquearse en la puerta"],"re":"Mantén el pasillo despejado para que los pasajeros puedan moverse y llegar a las salidas con seguridad."},
  {"id":17,"q":"Los pasajeros de pie en un autobús urbano deben permanecer:","opts":["Frente al parabrisas","Junto al asiento del conductor","Detrás de la línea de pasajeros de pie","Sobre los escalones"],"re":"Los pasajeros de pie deben permanecer detrás de la línea, lejos del conductor y del frente del autobús."},
  {"id":18,"q":"Una pequeña cantidad de medicina o suministros de emergencia que lleva un pasajero es:","opts":["Una razón para rechazar al pasajero","Lo mismo que una carga con rótulo","Algo que se guarda en el motor","Permitida como excepción limitada a la regla de materiales peligrosos"],"re":"Las cantidades pequeñas de suministros médicos o de emergencia son una excepción limitada a la regla de no llevar materiales peligrosos."},
  {"id":19,"q":"Mientras conduces, hablar con los pasajeros u otras distracciones se debe:","opts":["Fomentar durante todo el viaje","Hacer al girar","Evitar para poder concentrarte en conducir","Exigir en cada parada"],"re":"Evita hablar con los pasajeros y otras distracciones al conducir para mantener la atención en el camino."},
  {"id":20,"q":"Debes vigilar la altura de tu autobús y estar atento a:","opts":["La altura libre superior, como puentes y letreros","Solo la superficie del camino","La recepción de la radio","El color del cielo"],"re":"Vigila la altura libre y la altura del autobús para no golpear puentes, letreros o cables bajos."},
  {"id":21,"q":"Cargar combustible en un autobús con pasajeros a bordo en un espacio cerrado está:","opts":["Recomendado para ahorrar tiempo","Prohibido","Permitido si las ventanas están abiertas","Exigido antes de cada viaje"],"re":"No cargues combustible con pasajeros a bordo, sobre todo en un espacio cerrado, por el peligro de incendio."},
  {"id":22,"q":"Remolcar o empujar un autobús averiado con pasajeros a bordo es:","opts":["Una práctica diaria normal","Siempre preferible a esperar","Algo que se hace a velocidad de autopista","Algo solo para una emergencia, hasta el lugar seguro más cercano"],"re":"No remolques ni empujes un autobús averiado con pasajeros, salvo en una emergencia y solo hasta el lugar seguro más cercano."},
  {"id":23,"q":"Cuando debes informar a los pasajeros antes de un peligro, un buen momento es:","opts":["Después de que pasó el peligro","Solo si un pasajero pregunta dos veces","Antes de llegar a él, mientras aún es seguro","Nunca, para no alarmar"],"re":"Informa a los pasajeros sobre un peligro antes de llegar a él, mientras todavía es seguro hacerlo."},
  {"id":24,"q":"Si un pasajero conflictivo crea un peligro, el conductor debe:","opts":["Acelerar para terminar la ruta","Ignorarlo y seguir conduciendo rápido","Dejar el autobús encendido y alejarse","Manejarlo con seguridad, por ejemplo deteniéndose en un lugar seguro"],"re":"Maneja una alteración peligrosa con seguridad, lo que puede implicar detener el autobús en un lugar seguro."},
  {"id":25,"q":"Los objetos de mano sueltos dejados en el pasillo durante el viaje son un peligro porque pueden:","opts":["Mejorar la tracción","Hacer tropezar a los pasajeros y bloquear las salidas","Enfriar el autobús","Silenciar el motor"],"re":"Los objetos en el pasillo pueden hacer tropezar y bloquear las salidas; mantén el pasillo despejado durante el viaje."},
  {"id":26,"q":"Mantener toda tu atención en conducir el autobús te ayuda a:","opts":["Detectar peligros a tiempo y reaccionar a tiempo","Solo gastar menos combustible","Saltarte la inspección","Evitar usar los espejos"],"re":"La atención plena te permite ver los peligros a tiempo y reaccionar para mantener seguros a los pasajeros."},
  {"id":27,"q":"En un cruce de ferrocarril, debes detener el autobús:","opts":["Entre 15 y 50 pies antes del riel más cercano","Sobre las vías","Justo contra el riel","Solo si se ve un tren"],"re":"Detén el autobús entre 15 y 50 pies antes del riel más cercano en un cruce de ferrocarril."},
  {"id":28,"q":"Mientras el autobús cruza las vías del tren, no debes:","opts":["Mirar y escuchar","Seguir avanzando de forma constante","Estar atento a un segundo tren","Cambiar de marcha"],"re":"No cambies de marcha al cruzar las vías para que el autobús no se quede parado sobre el cruce."},
  {"id":29,"q":"Antes de cruzar las vías, el conductor debe:","opts":["Subir el volumen de la radio","Cerrar todas las rejillas","Mirar y escuchar, abriendo la puerta o la ventana si se requiere","Cruzar rápido"],"re":"Mira y escucha si viene un tren antes de cruzar, abriendo la puerta o la ventana cuando se requiera para oír mejor."},
  {"id":30,"q":"Un cruce de ferrocarril marcado como exento (exempt) significa que:","opts":["El autobús debe detenerse y cambiar de marcha","No se requiere que un autobús se detenga ahí","El cruce está cerrado","Solo los trenes pueden usarlo"],"re":"En un cruce marcado como exento, un autobús no debe hacer la parada normal, pero el conductor debe seguir atento."},
  {"id":31,"q":"En un puente levadizo sin señal ni encargado, debes detenerte al menos:","opts":["5 pies antes","Sobre el tramo móvil","100 yardas después","50 pies antes del tramo móvil"],"re":"Detente al menos 50 pies antes de un puente levadizo, salvo que una señal, luz o encargado controle el tránsito."},
  {"id":32,"q":"No necesitas detenerte en un puente levadizo cuando:","opts":["No hay agua debajo","Un semáforo o un encargado controla el tránsito","Es de día","El autobús está vacío"],"re":"No necesitas detenerte si un semáforo, una señal o un encargado u oficial controla el tránsito en el puente levadizo."},
  {"id":33,"q":"Una señal del puente levadizo que indica que es seguro cruzar significa que puedes:","opts":["Detenerte en el puente y esperar","Retroceder hacia el puente","Cruzar cuando esté despejado","Estacionarte en el tramo móvil"],"re":"Si el puente levadizo tiene una señal que indica que es seguro, puedes cruzar cuando el camino esté despejado."},
  {"id":34,"q":"Cuando te detienes en un cruce de ferrocarril, también debes:","opts":["Bloquear el cruce","Detenerte con la parte trasera sobre el riel","Hacer señas a otro tránsito para que cruce las vías","Elegir un espacio para que el autobús no quede parado sobre las vías"],"re":"Asegúrate de poder librar las vías por completo antes de arrancar, para que el autobús nunca se detenga sobre el cruce."},
  {"id":35,"q":"La velocidad indicada para una curva o rampa está pensada para:","opts":["Autos, así que un autobús debe reducir más","Solo autobuses","Caminos vacíos","Solo conducción nocturna"],"re":"Las velocidades indicadas en curvas y rampas son para autos; un autobús es más alto y pesado, así que reduce más."},
  {"id":36,"q":"No debes confiar en el enclavamiento de freno y acelerador del autobús urbano para:","opts":["Abrir las puertas","Mantener el autobús detenido en su lugar","Tocar el claxon","Enfriar el motor"],"re":"No confíes en el enclavamiento de freno y acelerador para retener el autobús; usa el freno de estacionamiento o de servicio."},
  {"id":37,"q":"Entrar a una curva demasiado rápido en un autobús puede hacer que:","opts":["Frene más rápido","Ahorre combustible","Se vuelque o derrape","Frene solo"],"re":"El exceso de velocidad en una curva puede hacer que un autobús alto se vuelque o derrape; reduce antes de la curva."},
  {"id":38,"q":"En una bajada larga en un autobús, el conductor debe:","opts":["Ir en neutral por inercia","Mantener los frenos pisados levemente todo el camino","Apagar el motor","Usar una marcha baja y frenado constante y controlado"],"re":"Usa una marcha baja y frenado constante y controlado en la bajada para que los frenos no se sobrecalienten ni pierdan eficacia."},
  {"id":39,"q":"El mejor lugar para reducir la velocidad antes de una curva es:","opts":["En el medio de la curva","Antes de entrar a la curva","Después de salir de la curva","Solo si sientes que el autobús se inclina"],"re":"Reduce antes de entrar a la curva; así puedes mantener algo de potencia dentro de ella para mejor control."},
  {"id":40,"q":"Comparado con un auto, un autobús cargado generalmente necesita:","opts":["Una distancia de frenado más larga","Una distancia de frenado más corta","Nada de frenado","Menos distancia de seguimiento"],"re":"Un autobús cargado es pesado y necesita una distancia de frenado más larga; mantén más espacio adelante."},
  {"id":41,"q":"Frenar de forma suave y gradual en un autobús ayuda a:","opts":["Lanzar hacia adelante a los pasajeros de pie","Desgastar las llantas más rápido","Vaciar los tanques de aire","Mantener a los pasajeros estables y cómodos"],"re":"El frenado suave y gradual mantiene estables a los pasajeros de pie y sentados y ayuda a evitar caídas."},
  {"id":42,"q":"En una bajada empinada, mantener los frenos pisados todo el camino puede causar:","opts":["Mejor control","Desvanecimiento del freno por sobrecalentamiento","Una parada más corta","Frenos más fríos"],"re":"Arrastrar los frenos en la bajada los sobrecalienta y causa desvanecimiento; usa una marcha baja y frenado controlado."},
  {"id":43,"q":"Durante una inspección posterior al viaje, debes recorrer el autobús para buscar:","opts":["Pasajeros dormidos y objetos perdidos","Un asiento libre para ti","La ruta más rápida a casa","Espacio extra para publicidad"],"re":"Tras el viaje, recorre el autobús para buscar pasajeros dormidos, objetos perdidos, daños y ventanas o puertas abiertas."},
  {"id":44,"q":"Después del viaje, las ventanas y puertas abiertas deben:","opts":["Dejarse abiertas toda la noche","Sellarse con pintura","Ignorarse hasta la mañana","Cerrarse, y reportar cualquier daño"],"re":"Cierra las ventanas y puertas abiertas en la revisión posterior al viaje y reporta cualquier daño que encuentres."},
  {"id":45,"q":"Debes evacuar un autobús cuando hay:","opts":["Un retraso menor de tránsito","Un pasajero conversador","Incendio, peligro de choque, una posición de parada insegura o una amenaza de materiales peligrosos","Lluvia ligera afuera"],"re":"Evacúa cuando hay incendio, peligro de choque, una posición de parada insegura o una amenaza de materiales peligrosos."},
  {"id":46,"q":"Saber usar las salidas de emergencia te permite:","opts":["Saltarte la inspección","Sacar a los pasajeros rápido y con seguridad en una emergencia","Evitar parar en las estaciones","Llevar más equipaje"],"re":"Conocer las salidas de emergencia te permite sacar a los pasajeros rápido y con seguridad cuando debes evacuar."},
  {"id":47,"q":"Si un pasajero se queda dormido al terminar la ruta, el recorrido posterior al viaje te ayuda a:","opts":["Encerrarlo toda la noche","Cobrarle una tarifa extra","Ignorar las filas traseras","Encontrarlo para que nadie quede en el autobús"],"re":"El recorrido encuentra a los pasajeros dormidos para que nadie quede encerrado por accidente en el autobús."},
  {"id":48,"q":"En una parada de emergencia, mantener seguros a los pasajeros puede incluir:","opts":["Decirles que se paren y se amontonen en la puerta","Mantenerlos calmados y guiarlos a una salida segura","Salir a toda velocidad con las puertas abiertas","Dejarlos sin instrucciones"],"re":"Mantén a los pasajeros calmados y guíalos a una salida segura para que evacúen de forma ordenada."},
  {"id":49,"q":"Si el autobús queda detenido en una posición insegura, como una curva sin visibilidad, debes:","opts":["Esperar adentro sin ninguna advertencia","Hacer que los pasajeros empujen el autobús","Considerar evacuar y advertir al tránsito que se acerca","Mantener las puertas cerradas con seguro"],"re":"Una posición de parada insegura puede requerir evacuación; protege a los pasajeros y advierte al tránsito que se acerca."},
  {"id":50,"q":"Tras reportar los defectos de la inspección posterior al viaje, el autobús debe:","opts":["Conducirse hasta que se descomponga","Repararse antes de volver a llevar pasajeros","Esconderse del mecánico","Usarse solo de noche"],"re":"Reporta los defectos tras el viaje para que el autobús se repare antes de volver a llevar pasajeros."}
];
